use crate::decoder::{decode, DecodedInstruction, Instruction, Register, ZkvmError};
pub struct Zkvm { pub regs: [u32; 32], pub pc: u32, pub mem: Vec<u8>, pub halted: bool }
impl Zkvm { pub fn execute(&mut self, inst: DecodedInstruction) -> Result<(), ZkvmError> { match inst.instruction { Instruction::Add => self.write_reg(inst.rd.unwrap(), self.read_reg(inst.rs1.unwrap()).wrapping_add(self.read_reg(inst.rs2.unwrap()))), Instruction::Sub => self.write_reg(inst.rd.unwrap(), self.read_reg(inst.rs1.unwrap()).wrapping_sub(self.read_reg(inst.rs2.unwrap()))), Instruction::Mul => self.write_reg(inst.rd.unwrap(), self.mul_limb(self.read_reg(inst.rs1.unwrap()), self.read_reg(inst.rs2.unwrap()))), Instruction::Div => { let (a, b) = (self.read_reg(inst.rs1.unwrap()) as i32, self.read_reg(inst.rs2.unwrap()) as i32); self.write_reg(inst.rd.unwrap(), if b == 0 { !0 } else if a == i32::MIN && b == -1 { a as u32 } else { (a / b) as u32 }) }, Instruction::Ecall => self.halted = true, _ => {} } if !matches!(inst.instruction, Instruction::Jal | Instruction::Jalr) { self.pc += 4; } Ok(()) } fn read_reg(&self, r: Register) -> u32 { self.regs[r as usize] } fn write_reg(&mut self, r: Register, v: u32) { if r != Register::X0 { self.regs[r as usize] = v; } } fn mul_limb(&self, a: u32, b: u32) -> u32 { let (a0, a1, b0, b1) = (a & 0xffff, a >> 16, b & 0xffff, b >> 16); let p0 = (a0 as u64) * (b0 as u64); let p1 = (a0 as u64) * (b1 as u64); let p2 = (a1 as u64) * (b0 as u64); p0.wrapping_add((p1.wrapping_add(p2)) << 16) as u32 } }
